<script>
import { getWorldPlugs } from '@/api/worldplugs'
export default {
  name: "WorldPlug",
  data() {
    return {
      worldplugs: null,
      isShowBytable: true
    }
  },
  created() {
    getWorldPlugs().then(data=>{
      this.worldplugs = data
    })
  }
}
</script>

<template>
  <el-tabs type="border-card">
    <el-tab-pane label="各国插头" >
      <el-button type="text" @click="isShowBytable = !isShowBytable">切换视图</el-button>
      <el-table :data="worldplugs" border v-if="isShowBytable">
        <!-- <el-table-column type="selection" width="65" align="center"></el-table-column> -->
        <el-table-column prop="id" label="ID" width="65" align="left"></el-table-column>
        <el-table-column label="图片" align="left" width="100">
          <template slot-scope="scope">
            <el-image :src="scope.row.poster" :preview-src-list="scope.row.images" style="width: 50px; height: 50px"></el-image>
          </template>
        </el-table-column>
        <el-table-column prop="type" label="类型" align="left" width="100"></el-table-column>
        <el-table-column prop="name" label="名称" align="left" width="250"></el-table-column>
        <el-table-column prop="description" label="描述" align="left" width="250" :show-overflow-tooltip="true"></el-table-column>
        <el-table-column label="使用国家" align="left" width="500">
          <template slot-scope="scope">
            <el-tag v-for="contry in scope.row.countries" :key="contry" style="margin-left: 10px">{{contry}}</el-tag>
          </template>
        </el-table-column>
        <el-table-column label="操作" align="left" >
          <template slot-scope="scope">
            <el-button type="text" @click="handleViewDetail(scope)">详情</el-button>
          </template>
        </el-table-column>
      </el-table>
      <el-row v-else>
        <el-col :span="3" v-for="(plug, index) in worldplugs" :key="plug.id" :offset="index % 5 ===0 ? '1' : '1'" style="margin-bottom: 15px">
          <el-card shadow="hover" :body-style="{padding: '10px'}">
            <el-image :src="plug.poster" :preview-src-list="plug.images"></el-image>
            <div class="plug-info">
              <h2 class="plug-name" style="display: inline; font-size: 14px; font-weight: 400;">{{ plug.name }}</h2>
              <el-button type="text" style="float: right;">查看详情</el-button>
            </div>
          </el-card>
        </el-col>
      </el-row>
    </el-tab-pane>
    <el-tab-pane label="工业插头">
      
    </el-tab-pane>
  </el-tabs>
</template>

<style >
  .plug-image {
    width: 50px;
    height: 50px;
  }
  .el-tooltip__popper.is-dark{
    max-width: 220px;
  }
  .plug-info {
    line-height: 36px;
    font-weight: 400;
  }
</style>


